# residual_risk.py
# Compute residual risk after controls are applied.

from dataclasses import dataclass

LIKELIHOOD_SCORE = {"rare": 1, "unlikely": 2, "possible": 3, "likely": 4, "almost_certain": 5}
IMPACT_SCORE = {"negligible": 1, "minor": 2, "moderate": 3, "major": 4, "catastrophic": 5}
CONTROL_REDUCTION = {"preventive": 0.5, "detective": 0.25, "corrective": 0.1}

@dataclass
class RiskCalculation:
    threat_id: str
    inherent_likelihood: str
    inherent_impact: str
    applied_controls: list[str]

    @property
    def inherent_score(self) -> float:
        return (LIKELIHOOD_SCORE[self.inherent_likelihood]
                * IMPACT_SCORE[self.inherent_impact])

    @property
    def control_reduction(self) -> float:
        return sum(CONTROL_REDUCTION.get(c, 0) for c in self.applied_controls)

    @property
    def residual_score(self) -> float:
        reduction = min(self.control_reduction, 0.85)
        return self.inherent_score * (1 - reduction)

    @property
    def residual_rating(self) -> str:
        s = self.residual_score
        if s <= 4: return "low"
        if s <= 9: return "medium"
        if s <= 15: return "high"
        return "critical"

# Example
calc = RiskCalculation(
    threat_id="TC-002",
    inherent_likelihood="likely",
    inherent_impact="major",
    applied_controls=["preventive", "preventive", "detective"]
)
print(f"Inherent: {calc.inherent_score}")       # 16
print(f"Residual: {calc.residual_score:.1f}")   # 16 * (1 - 0.85) = 2.4
print(f"Rating: {calc.residual_rating}")        # low
